 66→// --- Rate limiter ---
 67→
 68→type rateLimiter struct {
 69→	mu       sync.Mutex
 70→	attempts map[string][]time.Time
 71→	blocked  map[string]time.Time
 72→}
 73→
 74→var limiter = &rateLimiter{
 75→	attempts: make(map[string][]time.Time),
 76→	blocked:  make(map[string]time.Time),
 77→}
 78→
 79→func (rl *rateLimiter) isBlocked(ip string) bool {
 80→	rl.mu.Lock()
 81→	defer rl.mu.Unlock()
 82→
 83→	if until, ok := rl.blocked[ip]; ok {
 84→		if time.Now().Before(until) {
 85→			return true
 86→		}
 87→		delete(rl.blocked, ip)
 88→	}
 89→	return false
 90→}
 91→
 92→func (rl *rateLimiter) recordFailure(ip string) {
 93→	rl.mu.Lock()
 94→	defer rl.mu.Unlock()
 95→
 96→	now := time.Now()
 97→	cutoff := now.Add(-rateLimitWindow)
 98→
 99→	// Clean old attempts
100→	var recent []time.Time
101→	for _, t := range rl.attempts[ip] {
102→		if t.After(cutoff) {
103→			recent = append(recent, t)
104→		}
105→	}
106→	recent = append(recent, now)
107→	rl.attempts[ip] = recent
108→
109→	if len(recent) >= rateLimitMax {
110→		rl.blocked[ip] = now.Add(rateLimitBlock)
111→		delete(rl.attempts, ip)
112→	}
113→}
114→
115→func (rl *rateLimiter) clearAttempts(ip string) {
116→	rl.mu.Lock()
117→	defer rl.mu.Unlock()
118→	delete(rl.attempts, ip)
119→}
