132→func (cs *csrfStore) generate() string {
133→	b := make([]byte, 32)
134→	rand.Read(b)
135→	token := hex.EncodeToString(b)
136→
137→	cs.mu.Lock()
138→	defer cs.mu.Unlock()
139→
140→	// Clean expired tokens
141→	now := time.Now()
142→	for k, v := range cs.tokens {
143→		if now.Sub(v) > 10*time.Minute {
144→			delete(cs.tokens, k)
145→		}
146→	}
147→
148→	cs.tokens[token] = now
149→	return token
150→}
