152→func (cs *csrfStore) validate(token string) bool {
153→	cs.mu.Lock()
154→	defer cs.mu.Unlock()
155→
156→	if t, ok := cs.tokens[token]; ok {
157→		delete(cs.tokens, token)
158→		return time.Since(t) < 10*time.Minute
159→	}
160→	return false
161→}
