182→func makeSessionToken(username string) string {
183→	payload := fmt.Sprintf("%s:%d", username, time.Now().Unix())
184→	mac := hmac.New(sha256.New, sessionSecret)
185→	mac.Write([]byte(payload))
186→	sig := hex.EncodeToString(mac.Sum(nil))[:32]
187→	return fmt.Sprintf("%s:%s", payload, sig)
188→}
189→
190→func verifySessionToken(token string) bool {
191→	lastColon := strings.LastIndex(token, ":")
192→	if lastColon < 0 {
193→		return false
194→	}
195→	payload := token[:lastColon]
196→	sig := token[lastColon+1:]
197→
198→	mac := hmac.New(sha256.New, sessionSecret)
199→	mac.Write([]byte(payload))
200→	expected := hex.EncodeToString(mac.Sum(nil))[:32]
201→
202→	if !hmac.Equal([]byte(sig), []byte(expected)) {
203→		return false
204→	}
205→
206→	// Check expiry
207→	parts := strings.SplitN(payload, ":", 2)
208→	if len(parts) != 2 {
209→		return false
210→	}
211→	ts, err := strconv.ParseInt(parts[1], 10, 64)
212→	if err != nil {
213→		return false
214→	}
215→	return time.Now().Unix()-ts <= cookieMaxAge
216→}
