// --- Handlers ---

func handleAuthVerify(w http.ResponseWriter, r *http.Request) {
	if isAuthenticated(r) {
		w.WriteHeader(http.StatusOK)
	} else {
		http.Redirect(w, r, "/oauth2/login", http.StatusFound)
	}
}

func handleOAuth2Login(w http.ResponseWriter, r *http.Request) {
	if oauthConfig == nil {
		http.Error(w, "OAuth2 not configured", http.StatusInternalServerError)
		return
	}

	state := oauthStates.generate()
	authURL := fmt.Sprintf(
		"https://accounts.google.com/o/oauth2/v2/auth?client_id=%s&redirect_uri=%s&response_type=code&scope=%s&state=%s&access_type=online&prompt=select_account",
		url.QueryEscape(oauthConfig.ClientID),
		url.QueryEscape("https://attlas.uk/oauth2/callback"),
		url.QueryEscape("openid email"),
		url.QueryEscape(state),
	)
	http.Redirect(w, r, authURL, http.StatusFound)
}

func handleOAuth2Callback(w http.ResponseWriter, r *http.Request) {
	if oauthConfig == nil {
		http.Error(w, "OAuth2 not configured", http.StatusInternalServerError)
		return
	}

	// Validate state
	state := r.URL.Query().Get("state")
	if !oauthStates.validate(state) {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "Invalid or expired login request. Please try again.")
		return
	}

	// Check for error from Google
	if errMsg := r.URL.Query().Get("error"); errMsg != "" {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "Google sign-in was cancelled or failed.")
		return
	}

	code := r.URL.Query().Get("code")
	if code == "" {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "No authorization code received from Google.")
		return
	}

	// Exchange code for token
	tokenResp, err := http.PostForm("https://oauth2.googleapis.com/token", url.Values{
		"code":          {code},
		"client_id":     {oauthConfig.ClientID},
		"client_secret": {oauthConfig.ClientSecret},
		"redirect_uri":  {"https://attlas.uk/oauth2/callback"},
		"grant_type":    {"authorization_code"},
	})
	if err != nil {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "Failed to contact Google. Please try again.")
		return
	}
	defer tokenResp.Body.Close()

	var tokenData struct {
		AccessToken string `json:"access_token"`
		Error       string `json:"error"`
	}
	json.NewDecoder(tokenResp.Body).Decode(&tokenData)
	if tokenData.AccessToken == "" {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "Failed to authenticate with Google.")
		return
	}

	// Get user info
	userReq, _ := http.NewRequest("GET", "https://www.googleapis.com/oauth2/v2/userinfo", nil)
	userReq.Header.Set("Authorization", "Bearer "+tokenData.AccessToken)
	userResp, err := http.DefaultClient.Do(userReq)
	if err != nil {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "Failed to get user info from Google.")
		return
	}
	defer userResp.Body.Close()

	var userInfo struct {
		Email         string `json:"email"`
		VerifiedEmail bool   `json:"verified_email"`
	}
	json.NewDecoder(userResp.Body).Decode(&userInfo)

	if userInfo.Email == "" || !userInfo.VerifiedEmail {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, errorPageTemplate, "Could not verify your email address.")
		return
	}

	// Check against allowed emails
	allowed := false
	for _, e := range oauthConfig.AllowedEmails {
		if strings.EqualFold(e, userInfo.Email) {
			allowed = true
			break
		}
	}
	if !allowed {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprint(w, accessDeniedPage)
		return
	}

	// Create session
	sessionToken := makeSessionToken(userInfo.Email)
	http.SetCookie(w, &http.Cookie{
		Name:     cookieName,
		Value:    sessionToken,
		Path:     "/",
		MaxAge:   cookieMaxAge,
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
		Secure:   true,
	})
	http.Redirect(w, r, "/", http.StatusFound)
}

func handleLogout(w http.ResponseWriter, r *http.Request) {
	http.SetCookie(w, &http.Cookie{
		Name:   cookieName,
		Value:  "",
		Path:   "/",
		MaxAge: -1,
	})
	http.Redirect(w, r, "/oauth2/login", http.StatusFound)
}

func getSessionEmail(r *http.Request) string {
	token := getSessionCookie(r)
	if token == "" {
		return ""
	}
	lastColon := strings.LastIndex(token, ":")
	if lastColon < 0 {
		return ""
	}
	payload := token[:lastColon]
	parts := strings.SplitN(payload, ":", 2)
	if len(parts) != 2 {
		return ""
	}
	return parts[0]
}

func handleStatus(w http.ResponseWriter, r *http.Request) {
	sendJSON(w, map[string]interface{}{
		"vm": getVMInfo(),
		"user": map[string]string{
			"email": getSessionEmail(r),
		},
		"claude": map[string]bool{
			"installed":     isClaudeInstalled(),
			"authenticated": isClaudeLoggedIn(),
		},
		"services": getServicesStatus(),
	})
}

func handleClaudeLogin(w http.ResponseWriter, r *http.Request) {
	if isClaudeLoggedIn() {
		sendJSON(w, map[string]interface{}{"error": "Already logged in"})
		return
	}

	exec.Command("pkill", "-f", "claude-login-helper").Run()
	time.Sleep(1 * time.Second)

	for _, f := range []string{"/tmp/claude-login-url", "/tmp/claude-login-code", "/tmp/claude-login-result"} {
		os.Remove(f)
	}

	helperPath := filepath.Join(filepath.Dir(os.Args[0]), "claude-login-helper.py")
	if _, err := os.Stat(helperPath); err != nil {
		helperPath = filepath.Join(distDir, "..", "claude-login-helper.py")
	}

	logFile, _ := os.Create("/tmp/claude-login-helper.log")
	cmd := exec.Command("python3", helperPath)
	cmd.Stdout = logFile
	cmd.Stderr = logFile
	cmd.SysProcAttr = nil
	cmd.Start()

	var authURL string
	for i := 0; i < 60; i++ {
		data, err := os.ReadFile("/tmp/claude-login-url")
		if err == nil {
			authURL = strings.TrimSpace(string(data))
			if authURL != "" {
				break
			}
		}
		time.Sleep(1 * time.Second)
	}

	if authURL != "" {
		sendJSON(w, map[string]interface{}{"url": authURL})
	} else {
		logData, _ := os.ReadFile("/tmp/claude-login-helper.log")
		snippet := string(logData)
		if len(snippet) > 500 {
			snippet = snippet[:500]
		}
		sendJSON(w, map[string]interface{}{"error": fmt.Sprintf("Timed out waiting for URL. Log: %s", snippet)})
	}
}

func handleClaudeCode(w http.ResponseWriter, r *http.Request) {
	var body struct {
		Code string `json:"code"`
	}
	json.NewDecoder(r.Body).Decode(&body)
	if body.Code == "" {
		sendJSON(w, map[string]interface{}{"error": "No code provided."})
		return
	}

	os.WriteFile("/tmp/claude-login-code", []byte(body.Code), 0644)

	var result string
	for i := 0; i < 30; i++ {
		data, err := os.ReadFile("/tmp/claude-login-result")
		if err == nil {
			result = strings.TrimSpace(string(data))
			if result != "" {
				break
			}
		}
		time.Sleep(1 * time.Second)
	}

	if result == "SUCCESS" {
		sendJSON(w, map[string]interface{}{"success": true})
	} else if result != "" {
		sendJSON(w, map[string]interface{}{"error": result})
	} else {
		sendJSON(w, map[string]interface{}{"error": "Timed out waiting for login result."})
	}
}

func handleInstallService(w http.ResponseWriter, r *http.Request) {
	var body struct {
		ID string `json:"id"`
	}
	json.NewDecoder(r.Body).Decode(&body)

	svc := findService(body.ID)
	if svc == nil {
		sendJSON(w, map[string]interface{}{"error": fmt.Sprintf("Unknown service: %s", body.ID)})
		return
	}

	script := filepath.Join(attlasDir, "services", svc.Script)
	if _, err := os.Stat(script); err != nil {
		sendJSON(w, map[string]interface{}{"error": fmt.Sprintf("Script not found: %s", script)})
		return
	}

	cmd := exec.Command("bash", script)
	cmd.Dir = filepath.Join(attlasDir, "services")
	out, err := cmd.CombinedOutput()
	if err != nil {
		sendJSON(w, map[string]interface{}{"error": string(out)})
		return
	}

	exec.Command("sudo", "systemctl", "reload", "caddy").Run()
	sendJSON(w, map[string]interface{}{"success": true})
}

func handleUninstallService(w http.ResponseWriter, r *http.Request) {
	var body struct {
		ID string `json:"id"`
	}
	json.NewDecoder(r.Body).Decode(&body)

	svc := findService(body.ID)
	if svc == nil {
		sendJSON(w, map[string]interface{}{"error": fmt.Sprintf("Unknown service: %s", body.ID)})
		return
	}

	script := filepath.Join(attlasDir, "services", fmt.Sprintf("uninstall-%s.sh", svc.ID))
	if _, err := os.Stat(script); err != nil {
		sendJSON(w, map[string]interface{}{"error": fmt.Sprintf("Uninstall script not found: %s", script)})
		return
	}

	cmd := exec.Command("bash", script)
	cmd.Dir = filepath.Join(attlasDir, "services")
	out, err := cmd.CombinedOutput()
	if err != nil {
		sendJSON(w, map[string]interface{}{"error": string(out)})
		return
	}

	exec.Command("sudo", "systemctl", "reload", "caddy").Run()
	sendJSON(w, map[string]interface{}{"success": true})
}

// --- Helpers ---

func findService(id string) *Service {
	for _, s := range knownServices {
		if s.ID == id {
			return &s
		}
	}
	return nil
}

func sendJSON(w http.ResponseWriter, data interface{}) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(data)
}

func extractIP(r *http.Request) string {
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.SplitN(xff, ",", 2)
		return strings.TrimSpace(parts[0])
	}
	host, _, _ := strings.Cut(r.RemoteAddr, ":")
	return host
}

func serveStatic(w http.ResponseWriter, r *http.Request) {
	path := r.URL.Path
	if path == "/" {
		path = "/index.html"
	}

	filePath := filepath.Join(distDir, filepath.Clean(path))

	if !strings.HasPrefix(filePath, distDir) {
		http.NotFound(w, r)
		return
	}

	if info, err := os.Stat(filePath); err == nil && !info.IsDir() {
		contentType := mime.TypeByExtension(filepath.Ext(filePath))
		if contentType == "" {
			contentType = "application/octet-stream"
		}
		w.Header().Set("Content-Type", contentType)
		http.ServeFile(w, r, filePath)
		return
	}

	indexPath := filepath.Join(distDir, "index.html")
	if _, err := os.Stat(indexPath); err == nil {
		w.Header().Set("Content-Type", "text/html")
		http.ServeFile(w, r, indexPath)
		return
	}

	http.NotFound(w, r)
}

// --- Main ---

func main() {
	sessionSecret = loadOrCreateSecret()
	oauthConfig = loadOAuthConfig()

	// Resolve paths
	execPath, _ := os.Executable()
	execDir := filepath.Dir(execPath)
	distDir = filepath.Join(execDir, "frontend", "dist")
	home, _ := os.UserHomeDir()
	attlasDir = filepath.Join(home, "attlas")

	if _, err := os.Stat(distDir); err != nil {
		wd, _ := os.Getwd()
		distDir = filepath.Join(wd, "frontend", "dist")
	}

	mux := http.NewServeMux()

	// Auth
	mux.HandleFunc("/api/auth/verify", handleAuthVerify)
	mux.HandleFunc("GET /oauth2/login", handleOAuth2Login)
	mux.HandleFunc("GET /oauth2/callback", handleOAuth2Callback)
	mux.HandleFunc("/logout", handleLogout)

	// API
	mux.HandleFunc("/api/status", handleStatus)
	mux.HandleFunc("POST /api/claude-login", handleClaudeLogin)
	mux.HandleFunc("POST /api/claude-login/code", handleClaudeCode)
	mux.HandleFunc("POST /api/install-service", handleInstallService)
	mux.HandleFunc("POST /api/uninstall-service", handleUninstallService)

	// Static files (catch-all)
	mux.HandleFunc("/", serveStatic)

	addr := fmt.Sprintf("127.0.0.1:%d", port)
	log.Printf("Attlas server running on http://%s", addr)
	log.Printf("Serving frontend from %s", distDir)
	log.Fatal(http.ListenAndServe(addr, mux))
}

func init() {
	mime.AddExtensionType(".js", "application/javascript")
	mime.AddExtensionType(".css", "text/css")
	mime.AddExtensionType(".svg", "image/svg+xml")
	mime.AddExtensionType(".json", "application/json")
	mime.AddExtensionType(".woff2", "font/woff2")
}

import { useState, useEffect } from 'react'

function App() {
  const [vm, setVm] = useState(null)
  const [user, setUser] = useState(null)
  const [claude, setClaude] = useState(null)
  const [services, setServices] = useState([])
  const [toast, setToast] = useState(null)
  const [loginState, setLoginState] = useState('idle')
  const [authUrl, setAuthUrl] = useState('')
  const [code, setCode] = useState('')
  const [loginMsg, setLoginMsg] = useState(null)
  const [installing, setInstalling] = useState(null)
  const [uninstalling, setUninstalling] = useState(null)

  const showToast = (msg, color) => {
    setToast({ msg, color })
    setTimeout(() => setToast(null), 4000)
  }

  const fetchStatus = async () => {
    try {
      const res = await fetch('/api/status')
      const data = await res.json()
      setVm(data.vm)
      setUser(data.user)
      setClaude(data.claude)
      setServices(data.services)
    } catch (e) {
      console.error('Failed to fetch status', e)
    }
  }

  useEffect(() => { fetchStatus() }, [])

  const startLogin = async () => {
    setLoginState('waiting_url')
    setLoginMsg(null)
    try {
      const res = await fetch('/api/claude-login', { method: 'POST' })
      const data = await res.json()
      if (data.url) {
        setAuthUrl(data.url)
        setLoginState('waiting_code')
      } else {
        setLoginMsg({ text: data.error || 'Failed to start login', error: true })
        setLoginState('idle')
      }
    } catch (e) {
      setLoginMsg({ text: e.message, error: true })
      setLoginState('idle')
    }
  }

  const submitCode = async () => {
    if (!code.trim()) return
    setLoginMsg({ text: 'Submitting code...', error: false })
    try {
      const res = await fetch('/api/claude-login/code', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ code: code.trim() })
      })
      const data = await res.json()
      if (data.success) {
        setLoginMsg({ text: 'Logged in!', error: false })
        setLoginState('idle')
        setCode('')
        setTimeout(fetchStatus, 1500)
      } else {
        setLoginMsg({ text: data.error || 'Login failed', error: true })
      }
    } catch (e) {
      setLoginMsg({ text: e.message, error: true })
    }
  }

  const installService = async (id) => {
    if (!confirm(`Install ${id}?`)) return
    setInstalling(id)
    showToast(`Installing ${id}...`, '#5a67d8')
    try {
      const res = await fetch('/api/install-service', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id })
      })
      const data = await res.json()
      if (data.success) {
        showToast(`${id} installed!`, '#48bb78')
        setTimeout(fetchStatus, 1000)
      } else {
        showToast(data.error || 'Install failed', '#fc8181')
      }
    } catch (e) {
      showToast(e.message, '#fc8181')
    } finally {
      setInstalling(null)
    }
  }

  const uninstallService = async (id) => {
    if (!confirm(`Uninstall ${id}? This will stop and remove the service.`)) return
    setUninstalling(id)
    showToast(`Uninstalling ${id}...`, '#e53e3e')
    try {
      const res = await fetch('/api/uninstall-service', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id })
      })
      const data = await res.json()
      if (data.success) {
        showToast(`${id} uninstalled`, '#48bb78')
        setTimeout(fetchStatus, 1000)
      } else {
        showToast(data.error || 'Uninstall failed', '#fc8181')
      }
    } catch (e) {
      showToast(e.message, '#fc8181')
    } finally {
      setUninstalling(null)
    }
  }

  if (!vm) return <p style={{ color: '#888', textAlign: 'center', marginTop: '3rem' }}>Loading...</p>

  return (
    <>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <h1 style={{ margin: 0 }}>I am alive!</h1>
          <div className="subtitle">Attlas VM Dashboard</div>
        </div>
        {user?.email && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', color: '#888', fontSize: '0.85rem' }}>
            <span>{user.email}</span>
            <a href="/logout" style={{ color: '#fc8181', textDecoration: 'none', fontSize: '0.8rem' }}>logout</a>
          </div>
        )}
      </div>

      <h2>VM Info</h2>
      <table>
        <tbody>
          <tr><td className="label">Name</td><td>{vm.name}</td></tr>
          <tr><td className="label">Zone</td><td>{vm.zone}</td></tr>
          <tr><td className="label">External IP</td><td>{vm.external_ip}</td></tr>
          <tr><td className="label">Domain</td><td><a href={`https://${vm.domain}/`}>{vm.domain}</a></td></tr>
        </tbody>
      </table>

      <h2>Claude Code</h2>
      {!claude?.installed ? (
        <div className="muted">Not installed. Run ~/attlas/base-setup/setup.sh</div>
      ) : claude?.authenticated ? (
        <div className="dot-green">Authenticated</div>
      ) : (
        <>
          <div className="dot-red">Not authenticated</div>
          {loginState === 'idle' && (
            <div style={{ marginTop: '0.8rem' }}>
              <button className="btn btn-primary" onClick={startLogin}>
                Login to Claude Code
              </button>
            </div>
          )}
          {loginState === 'waiting_url' && (
            <div style={{ marginTop: '0.8rem', color: '#888' }}>Starting login...</div>
          )}
          {loginState === 'waiting_code' && (
            <div className="login-box">
              <p>1. Click to authenticate:</p>
              <a href={authUrl} target="_blank" rel="noopener noreferrer" style={{ wordBreak: 'break-all' }}>
                {authUrl}
              </a>
              <div style={{ marginTop: '1rem' }}>
                <p>2. Paste the authentication code:</p>
                <div className="row" style={{ marginTop: '0.5rem' }}>
                  <input
                    className="input"
                    type="text"
                    placeholder="Paste code from browser..."
                    value={code}
                    onChange={e => setCode(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && submitCode()}
                  />
                  <button className="btn btn-success" onClick={submitCode}>Submit</button>
                </div>
              </div>
            </div>
          )}
          {loginMsg && (
            <div className={loginMsg.error ? 'msg-error' : 'msg-success'} style={{ marginTop: '0.5rem' }}>
              {loginMsg.text}
            </div>
          )}
        </>
      )}

      <h2>Services</h2>
      <table>
        <tbody>
          <tr className="table-header">
            <td>Service</td><td>Status</td><td>Path</td>
          </tr>
          {services.map(svc => (
            <tr key={svc.id}>
              {svc.installed ? (
                <>
                  <td className={svc.running ? 'dot-green' : 'dot-red'}>{svc.name}</td>
                  <td>{svc.running ? 'running' : 'stopped'}</td>
                  <td>
                    {svc.path ? <a href={svc.path} target="_blank" rel="noopener noreferrer">{svc.path}</a> : '\u2014'}
                    {' '}
                    <button
                      className="btn btn-uninstall"
                      onClick={() => uninstallService(svc.id)}
                      disabled={uninstalling === svc.id}
                      title="Uninstall"
                    >
                      {uninstalling === svc.id ? '...' : '\u2715'}
                    </button>
                  </td>
                </>
              ) : (
                <>
                  <td className="dot-grey muted">{svc.name}</td>
                  <td className="muted">not installed</td>
                  <td>
                    <button
                      className="btn btn-sm"
                      onClick={() => installService(svc.id)}
                      disabled={installing === svc.id}
                    >
                      {installing === svc.id ? 'Installing...' : 'Install'}
                    </button>
                  </td>
                </>
              )}
            </tr>
          ))}
        </tbody>
      </table>

      {toast && (
        <div className="toast" style={{ background: toast.color }}>
          {toast.msg}
        </div>
      )}
    </>
  )
}

export default App

