input.command:
python3 -c "
import json, sys

msgs = []
with open('$HOME/.claude/projects/-Users-kerima-weller-ok/147cad6f-b227-48a6-89e6-607faed59819.jsonl') as f:
    for line in f:
        try:
            obj = json.loads(line)
            if obj.get('type') == 'human' or obj.get('role') == 'user':
                # Extract text from content
                content = obj.get('content', obj.get('message', ''))
                if isinstance(content, list):
                    texts = [c.get('text','') for c in content if isinstance(c, dict) and c.get('type') == 'text']
                    content = ' '.join(texts)
                if isinstance(content, str) and content.strip() and len(content.strip()) > 5:
                    ts = obj.get('timestamp', obj.get('ts', ''))
                    msgs.append((ts, content.strip()[:200]))
        except:
            pass

for ts, msg in msgs:
    print(f'[{ts}] {msg}')
" 2>&1 | head -80

